import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/* ===================== Helpers ===================== */
const PAGE_SIZE = 10;
const VND = (v) => (Number(v || 0)).toLocaleString("vi-VN");

const parseVND = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const num = String(s).replace(/[^\d]/g, "");
    return Number(num || 0);
};

const todayStr = () => {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
};

const METHOD_OPTS = [
    { label: "Chuyển khoản", value: "BANK_TRANSFER" },
    { label: "Tiền mặt", value: "CASH" },
];

const STATUS_OPTS = [
    { label: "Chờ xác nhận", value: "PENDING" },
    { label: "Đã thanh toán", value: "PAID" },
];

const toLabel = (opts, v) =>
    opts.find((o) => o.value === v || o.label === v)?.label || v || "";

const toValue = (opts, l) =>
    opts.find((o) => o.label === l || o.value === l)?.value || l;

function normalizeList(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1 }
        : { list: d?.content || [], pages: d?.totalPages || 1 };
}

function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object") return ["role", "name", "authority"].forEach((k) => x[k] && S.add(String(x[k]).toUpperCase()));
    };
    add(user.role);
    add(user.roles);
    add(user.authorities);
    if (S.size === 0) return true; // không rõ schema -> vẫn cho hiện nút
    return allow.some((r) => S.has(r));
}

/* ===================== Component ===================== */
export default function Payments() {
    const { user } = useAuth();
    const canEdit = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);

    // data
    const [contracts, setContracts] = useState([]);
    const [rows, setRows] = useState([]);

    // filters/paging
    const [selectedContractId, setSelectedContractId] = useState("");
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // modal/form
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [saving, setSaving] = useState(false);
    const [form, setForm] = useState({
        contractId: "",
        date: todayStr(),
        amount: "", // formatted string
        method: "Chuyển khoản",
        confirmer: "",
        status: "Chờ xác nhận",
    });

    /* ---------- load contracts ---------- */
    useEffect(() => {
        (async () => {
            try {
                const { data } = await api.get("/api/contracts", {
                    params: { page: 0, size: 1000, sort: "id,desc" },
                });
                const list = Array.isArray(data) ? data : data?.content || [];
                setContracts(list);
                // default chọn hợp đồng đầu tiên nếu chưa chọn
                if (!selectedContractId && list[0]?.id) {
                    setSelectedContractId(String(list[0].id));
                }
            } catch (e) {
                console.error("Load contracts failed:", e);
            }
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    /* ---------- load payments ---------- */
    useEffect(() => {
        loadPayments(0);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedContractId]);

    useEffect(() => {
        loadPayments(page);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page]);

    async function loadPayments(p) {
        setLoading(true);
        try {
            const { data } = await api.get("/api/payments", {
                params: {
                    page: p,
                    size: PAGE_SIZE,
                    sort: "id,desc",

                    ...(selectedContractId ? { contractId: selectedContractId } : {}),
                },
            });
            const { list, pages } = normalizeList(data);
            setRows(list);
            setTotalPages(pages);
            setPage(p);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
            setPage(0);
        } finally {
            setLoading(false);
        }
    }

    /* ---------- derived ---------- */
    const contractMap = useMemo(() => {
        const m = new Map();
        contracts.forEach((ct) => {
            m.set(String(ct.id), ct);
        });
        return m;
    }, [contracts]);

    const currentContract = selectedContractId
        ? contractMap.get(String(selectedContractId))
        : null;

    const summary = useMemo(() => {
        if (!currentContract) return null;
        return {
            total: currentContract.totalAmount || 0,
            paid: currentContract.paidAmount || 0,
            remain: currentContract.remainingAmount ?? Math.max(
                0,
                (currentContract.totalAmount || 0) - (currentContract.paidAmount || 0)
            ),
            code: currentContract.contractCode || currentContract.code || `HD-${currentContract.id}`,
            customer:
                currentContract.customer?.name || currentContract.customerName || "",
        };
    }, [currentContract]);

    /* ---------- open modal ---------- */
    function openCreate() {
        setEditing(null);
        const defaultContractId =
            selectedContractId || (contracts[0]?.id ? String(contracts[0].id) : "");
        setForm({
            contractId: defaultContractId,
            date: todayStr(),
            amount: "",
            method: "Chuyển khoản",
            confirmer: "",
            status: "Chờ xác nhận",
        });
        setShow(true);
    }

    function openEdit(p) {
        setEditing(p);
        setForm({
            contractId: String(p.contractId || p.contract?.id || selectedContractId || ""),
            date: p.paymentDate || p.date || todayStr(),
            amount: VND(p.amount ?? p.money ?? 0),
            method: toLabel(METHOD_OPTS, p.paymentMethod || p.method || "BANK_TRANSFER"),
            confirmer: p.confirmedBy || p.confirmer || "",
            status: toLabel(STATUS_OPTS, p.status || p.paymentStatus || "PENDING"),
        });
        setShow(true);
    }

    /* ---------- save/remove ---------- */
    async function save(e) {
        e.preventDefault();
        const payload = {
            contractId: Number(form.contractId),
            paymentDate: form.date,
            amount: parseVND(form.amount),
            paymentMethod: toValue(METHOD_OPTS, form.method),
            confirmedBy: form.confirmer?.trim() || null,
            status: toValue(STATUS_OPTS, form.status),
        };

        // validate cơ bản
        if (!payload.contractId) return alert("Vui lòng chọn hợp đồng");
        if (!payload.paymentDate) return alert("Vui lòng chọn ngày");
        if (!payload.amount || payload.amount <= 0)
            return alert("Số tiền phải lớn hơn 0");

        setSaving(true);
        try {
            if (editing) {
                await api.put(`/api/payments/${editing.id}`, payload);
            } else {
                await api.post("/api/payments", payload);
            }
            setShow(false);
            // reload cả payments và contracts (để cập nhật đã thu/còn lại)
            await Promise.all([loadPayments(0), reloadContractsOnly()]);
        } catch (err) {
            console.error(err);
            alert(err?.response?.data?.message || "Lưu thanh toán thất bại");
        } finally {
            setSaving(false);
        }
    }

    async function reloadContractsOnly() {
        try {
            const { data } = await api.get("/api/contracts", {
                params: { page: 0, size: 1000, sort: "id,desc" },
            });
            const list = Array.isArray(data) ? data : data?.content || [];
            setContracts(list);
        } catch (e) {
            console.error("Reload contracts failed:", e);
        }
    }

    async function removeRow(row) {
        if (!window.confirm("Xoá đợt thanh toán này?")) return;
        try {
            await api.delete(`/api/payments/${row.id}`);
            await Promise.all([loadPayments(page), reloadContractsOnly()]);
        } catch (err) {
            console.error(err);
            alert(err?.response?.data?.message || "Xoá thanh toán thất bại");
        }
    }

    /* ---------- render ---------- */
    return (
        <div className="space-y-5">
            {/* Header */}
            <div className="flex items-center justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold">Thanh toán</h2>
                    <p className="text-sm text-slate-500">
                        Quản lý các đợt thanh toán theo hợp đồng
                    </p>
                </div>

                <div className="flex items-center gap-3">
                    {/* Filter theo HĐ */}
                    <select
                        value={selectedContractId}
                        onChange={(e) => {
                            setSelectedContractId(e.target.value);
                            setPage(0);
                        }}
                        className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[280px]"
                        title="Chọn hợp đồng"
                    >
                        {contracts.map((ct) => {
                            const code = ct.contractCode || ct.code || `HD-${ct.id}`;
                            const cus =
                                ct.customer?.name || ct.customerName || "";
                            return (
                                <option key={ct.id} value={ct.id}>
                                    {code} - {cus}
                                </option>
                            );
                        })}
                    </select>

                    {canEdit && (
                        <button
                            onClick={openCreate}
                            className="px-3 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700"
                        >
                            Thêm đợt thanh toán
                        </button>
                    )}
                </div>
            </div>

            {/* Summary for current contract */}
            {summary && (
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Tổng giá trị</div>
                        <div className="text-lg font-semibold tabular-nums">{VND(summary.total)} đ</div>
                    </div>
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Đã thu</div>
                        <div className="text-lg font-semibold tabular-nums">{VND(summary.paid)} đ</div>
                    </div>
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Còn lại</div>
                        <div className="text-lg font-semibold tabular-nums">{VND(summary.remain)} đ</div>
                    </div>
                </div>
            )}

            {/* Table */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Ngày</th>
                            <th className="px-4 py-3 text-left">Số tiền</th>
                            <th className="px-4 py-3 text-left">Phương thức</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-left">Xác nhận</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((p) => {
                                const code =
                                    p.contractCode ||
                                    p.contract?.contractCode ||
                                    p.contract?.code ||
                                    (p.contractId ? "HD-" + p.contractId : "");
                                const mLabel = toLabel(METHOD_OPTS, p.paymentMethod || p.method);
                                const sLabel = toLabel(STATUS_OPTS, p.status || p.paymentStatus);
                                return (
                                    <tr key={p.id} className="hover:bg-indigo-50/40">
                                        <td className="px-4 py-3 font-medium">{code}</td>
                                        <td className="px-4 py-3">{p.paymentDate || p.date}</td>
                                        <td className="px-4 py-3 tabular-nums">{VND(p.amount ?? p.money)} đ</td>
                                        <td className="px-4 py-3">{mLabel || "-"}</td>
                                        <td className="px-4 py-3">
                        <span
                            className={
                                "px-2 py-0.5 rounded-full text-xs " +
                                ((sLabel || "") === "Đã thanh toán"
                                    ? "bg-emerald-100 text-emerald-700"
                                    : "bg-amber-100 text-amber-700")
                            }
                        >
                          {sLabel || "-"}
                        </span>
                                        </td>
                                        <td className="px-4 py-3">{p.confirmedBy || p.confirmer || "-"}</td>
                                        <td className="px-4 py-3 text-right">
                                            {canEdit ? (
                                                <div className="inline-flex gap-2">
                                                    <button
                                                        onClick={() => openEdit(p)}
                                                        className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                                    >
                                                        Sửa
                                                    </button>
                                                    <button
                                                        onClick={() => removeRow(p)}
                                                        className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                    >
                                                        Xóa
                                                    </button>
                                                </div>
                                            ) : (
                                                <span className="text-slate-400">—</span>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 items-center">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal */}
            {show && canEdit && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">
                                {editing ? "Sửa đợt thanh toán" : "Thêm đợt thanh toán"}
                            </div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShow(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Hợp đồng</label>
                                <select
                                    required
                                    value={form.contractId}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, contractId: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {contracts.map((ct) => {
                                        const code = ct.contractCode || ct.code || `HD-${ct.id}`;
                                        const cus =
                                            ct.customer?.name || ct.customerName || "";
                                        return (
                                            <option key={ct.id} value={ct.id}>
                                                {code} - {cus}
                                            </option>
                                        );
                                    })}
                                </select>
                            </div>

                            {/* Ngày */}
                            <div>
                                <label className="text-sm text-slate-600">Ngày</label>
                                <input
                                    required
                                    type="date"
                                    value={form.date}
                                    onChange={(e) => setForm((f) => ({ ...f, date: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            {/* Số tiền */}
                            <div>
                                <label className="text-sm text-slate-600">Số tiền (đ)</label>
                                <input
                                    required
                                    type="text"
                                    inputMode="numeric"
                                    pattern="[0-9\.]*"
                                    placeholder="VD: 200.000.000"
                                    value={form.amount}
                                    onChange={(e) =>
                                        setForm((f) => ({
                                            ...f,
                                            amount: VND(parseVND(e.target.value)),
                                        }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow tabular-nums"
                                />
                                {/* cảnh báo nhẹ nếu vượt còn lại */}
                                {(() => {
                                    const ct = contractMap.get(String(form.contractId));
                                    const remain =
                                        ct?.remainingAmount ??
                                        Math.max(0, (ct?.totalAmount || 0) - (ct?.paidAmount || 0));
                                    const val = parseVND(form.amount);
                                    if (ct && val > remain) {
                                        return (
                                            <div className="mt-1 text-xs text-amber-600">
                                                Lưu ý: Số tiền nhập lớn hơn số còn lại ({VND(remain)} đ).
                                            </div>
                                        );
                                    }
                                    return null;
                                })()}
                            </div>

                            {/* Phương thức */}
                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select
                                    value={form.method}
                                    onChange={(e) => setForm((f) => ({ ...f, method: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {METHOD_OPTS.map((o) => (
                                        <option key={o.value} value={o.label}>
                                            {o.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Người xác nhận */}
                            <div>
                                <label className="text-sm text-slate-600">Người xác nhận</label>
                                <input
                                    placeholder="VD: Kế toán A"
                                    value={form.confirmer}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, confirmer: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            {/* Trạng thái */}
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select
                                    value={form.status}
                                    onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {STATUS_OPTS.map((o) => (
                                        <option key={o.value} value={o.label}>
                                            {o.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Sau thu (xem trước) */}
                            <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-3 pt-1">
                                {(() => {
                                    const ct = contractMap.get(String(form.contractId));
                                    const total = ct?.totalAmount || 0;
                                    const paid = ct?.paidAmount || 0;
                                    const remain =
                                        ct?.remainingAmount ?? Math.max(0, total - paid);
                                    const val = parseVND(form.amount);
                                    const after = Math.max(0, remain - val);
                                    return (
                                        <>
                                            <div className="rounded-xl bg-slate-50 px-4 py-3">
                                                <div className="text-xs text-slate-500">Tổng giá trị</div>
                                                <div className="font-semibold tabular-nums">{VND(total)} đ</div>
                                            </div>
                                            <div className="rounded-xl bg-slate-50 px-4 py-3">
                                                <div className="text-xs text-slate-500">Đã thu</div>
                                                <div className="font-semibold tabular-nums">{VND(paid)} đ</div>
                                            </div>
                                            <div className="rounded-xl bg-slate-50 px-4 py-3">
                                                <div className="text-xs text-slate-500">Sau thu</div>
                                                <div className="font-semibold tabular-nums">{VND(after)} đ</div>
                                            </div>
                                        </>
                                    );
                                })()}
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                    disabled={saving}
                                >
                                    Hủy
                                </button>
                                <button
                                    className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50"
                                    disabled={saving}
                                >
                                    {saving ? "Đang lưu..." : "Lưu"}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
